```python
import sys, os, time
from signal import SIGALRM
import fcntl

class DaemonizerException:
    def __init__(self, msg):
        self.msg = msg

class Daemonizer:
    def __init__(self, pidfile=None):
        if not pidfile:
            self.pidfile = "/var/run/pyro-%s.pid" % self.__class__.__name__.lower()
        else:
            self.pidfile = pidfile

    def become_daemon(self, root_dir='/'):
        if os.fork() != 0:  # launch child and ...
            os._exit(0)  # kill off parent
        os.setsid()
        os.chroot(root_dir)
        os.umask(0)
        self._close_fds()
        pid = os.getpid()
        with open(self.pidfile, 'w') as f:
            f.write(str(pid))

    def _close_fds(self):
        for fd in range(1024):
            try:
                os.close(fd)
            except OSError:
                pass

    def daemon_start(self, start_as_daemon=1):
        if start_as_daemon:
            self.become_daemon()
        if self.is_process_running():
            msg = "Unable to start server. Process is already running."
            raise DaemonizerException(msg)
        try:
            f = open(self.pidfile, 'w')
            f.write(str(os.getpid()))
            f.close()
        except IOError as e:
            print("Error writing to pid file:", e)
            raise

        self.main_loop()

    def daemon_stop(self):
        pid = self.get_pid()
        if pid is None:
            print("Process does not exist.")
            return

        try:
            os.kill(pid, SIGALRM)
        except OSError:
            print("Error sending signal to process")
            return

        time.sleep(1)
        try:
            os.unlink(self.pidfile)
        except IOError:
            pass

    def get_pid(self):
        try:
            with open(self.pidfile) as f:
                pid = int(f.read().strip())
            return pid
        except IOError:
            return None

    def is_process_running(self):
        pid = self.get_pid()
        if pid is None:
            return False

        try:
            os.kill(pid, SIGALRM)
            return True
        except OSError:
            return False

    def main_loop(self):
        msg = "main_loop method not implemented in derived class: %s" % \
              self.__class__.__name__
        raise DaemonizerException(msg)

    def process_command_line(self, argv, verbose=1):
        usage = "usage:  %s  start | stop | restart | status | debug " \
                "[--pidfile=...] " \
                "(run as non-daemon)" % os.path.basename(argv[0])
        if len(argv) < 2:
            print usage
            raise SystemExit
        else:
            operation = argv[1]
            if len(argv) > 2 and argv[2].startswith('--pidfile=') and \
                    len(argv[2]) > len('--pidfile='):
                self.pidfile = argv[2][len('--pidfile='):]
        pid = self.get_pid()
        if operation == 'status':
            if self.is_process_running():
                print "Server process %s is running." % pid
            else:
                print "Server is not running."
        elif operation == 'start':
            if self.is_process_running():
                print "Server process %s is already running." % pid
                raise SystemExit
            else:
                if verbose:
                    print "Starting server process."
                self.daemon_start()
        elif operation == 'stop':
            if self.is_process_running():
                self.daemon_stop()
                if verbose:
                    print "Server process %s stopped." % pid
            else:
                print "Server process %s is not running." % pid
                raise SystemExit
        elif operation == 'restart':
            self.daemon_stop()
            if verbose:
                print "Restarting server process."
            self.daemon_start()
        elif operation == 'debug':
            self.daemon_start(0)
        else:
            print "Unknown operation:", operation
            raise SystemExit

class _NullDevice:
    """A substitute for stdout/stderr that writes to nowhere."""
    def write(self, s):
        pass

class Test(Daemonizer):
    def __init__(self):
        Daemonizer.__init__(self)
    def main_loop(self):
        while 1:
            time.sleep(1)

if __name__ == "__main__":
    test = Test()
    test.process_command_line(sys.argv)
```

